import{_ as n,c as a,o as s,a5 as t}from"./chunks/framework.CgT1UzWm.js";const u=JSON.parse('{"title":"Changelog v3.21.0","description":"NpgsqlRest v3.21.0: Per-connection routine discovery (ReadMetadataFromConnections) — endpoints execute where they were discovered, no more duplicating routines on the default database. Plus routed endpoint verification, environment variable fallback values, .env loaded by default, and the --install-skill command…","frontmatter":{"description":"NpgsqlRest v3.21.0: Per-connection routine discovery (ReadMetadataFromConnections) — endpoints execute where they were discovered, no more duplicating routines on the default database. Plus routed endpoint verification, environment variable fallback values, .env loaded by default, and the --install-skill command…","head":[["link",{"rel":"canonical","href":"https://npgsqlrest.github.io/guide/changelog/v3.21.0.html"}],["meta",{"property":"og:url","content":"https://npgsqlrest.github.io/guide/changelog/v3.21.0.html"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:title","content":"Changelog v3.21.0"}],["meta",{"property":"og:description","content":"NpgsqlRest v3.21.0: Per-connection routine discovery (ReadMetadataFromConnections) — endpoints execute where they were discovered, no more duplicating routines on the default database. Plus routed endpoint verification, environment variable fallback values, .env loaded by default, and the --install-skill command…"}],["meta",{"property":"og:image","content":"https://npgsqlrest.github.io/og-image.png"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Changelog v3.21.0"}],["meta",{"name":"twitter:description","content":"NpgsqlRest v3.21.0: Per-connection routine discovery (ReadMetadataFromConnections) — endpoints execute where they were discovered, no more duplicating routines on the default database. Plus routed endpoint verification, environment variable fallback values, .env loaded by default, and the --install-skill command…"}],["meta",{"name":"twitter:image","content":"https://npgsqlrest.github.io/og-image.png"}]]},"headers":[],"relativePath":"guide/changelog/v3.21.0.md","filePath":"guide/changelog/v3.21.0.md","lastUpdated":1782480183000}'),i={name:"guide/changelog/v3.21.0.md"};function o(l,e,r,c,d,h){return s(),a("div",null,e[0]||(e[0]=[t(`<h1 id="changelog-v3-21-0" tabindex="-1">Changelog v3.21.0 <a class="header-anchor" href="#changelog-v3-21-0" aria-label="Permalink to &quot;Changelog v3.21.0&quot;">​</a></h1><h2 id="version-3-21-0-2026-07-12" tabindex="-1">Version <a href="https://github.com/NpgsqlRest/NpgsqlRest/tree/3.21.0" target="_blank" rel="noreferrer">3.21.0</a> (2026-07-12) <a class="header-anchor" href="#version-3-21-0-2026-07-12" aria-label="Permalink to &quot;Version [3.21.0](https://github.com/NpgsqlRest/NpgsqlRest/tree/3.21.0) (2026-07-12)&quot;">​</a></h2><p><a href="https://github.com/NpgsqlRest/NpgsqlRest/compare/3.20.0...3.21.0" target="_blank" rel="noreferrer">Full Changelog</a></p><p>This release removes the single-connection assumption from multiple-connection setups: routine metadata can now be <strong>discovered per connection</strong> (<code>ReadMetadataFromConnections</code>) with endpoints executing on the connection they were discovered from, plus opt-in <strong>verification of <code>@connection</code>-routed endpoints</strong> (<code>VerifyRoutedEndpoints</code>). Also included: <strong>environment variable fallback values</strong> (<code>{!NAME:fallback}</code>) unified across configuration, static files, and annotations; a <strong><code>.env</code> file loaded by default</strong>; the <strong><code>--install-skill</code></strong> command for the Claude Code skill; a new CLI logo; and a set of multi-connection fixes.</p><blockquote><p>Note: version 3.20.1 was never released — its changes are included in this release.</p></blockquote><h3 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h3><h4 id="per-connection-routine-discovery-readmetadatafromconnections" tabindex="-1">Per-connection routine discovery: <code>ReadMetadataFromConnections</code> <a class="header-anchor" href="#per-connection-routine-discovery-readmetadatafromconnections" aria-label="Permalink to &quot;Per-connection routine discovery: \`ReadMetadataFromConnections\`&quot;">​</a></h4><p>Until now, routine metadata (functions and procedures) was always discovered on a <strong>single</strong> connection, while the <code>connection</code> annotation only changed where a request <em>executes</em>. That silently assumed every named connection has identical routine metadata — true for read replicas and shards, but wrong for setups where different databases host different routines (OLTP + OLAP/DW): a routine living only on the OLAP database had to be <strong>duplicated on the default database</strong> (with its annotation) just to be discovered, even though it was never called there.</p><p>That requirement is gone:</p><details class="code-collapsible" open><summary>json</summary><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">{</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">  &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">ConnectionStrings</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> {</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">    &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">Default</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> &quot;Host=localhost;Port=5432;Database=oltp;Username=postgres;Password=postgres&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">,</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">    &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">olap</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> &quot;Host=warehouse;Port=5432;Database=olap;Username=postgres;Password=postgres&quot;</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">  },</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">  &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">NpgsqlRest</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> {</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">    &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">RoutineOptions</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> {</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">      &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">ReadMetadataFromConnections</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> [</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> &quot;Default&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">,</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> &quot;olap&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> ]</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">    }</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">  }</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div></details><ul><li>Routine metadata is read from <strong>each listed connection</strong> (one routine source per name; all other <code>RoutineOptions</code> settings and the global schema/name filters are shared).</li><li><strong>Endpoints execute on the connection they were discovered from</strong> — a routine on the <code>olap</code> database is discovered there and runs there, annotations included, with nothing extra to configure. An explicit <code>connection</code> comment annotation still wins.</li><li>The list <em>replaces</em> the default — include the main connection&#39;s name (as above) to keep serving its routines.</li><li>Setting the key <strong>implicitly enables multiple connections</strong> — no <code>UseMultipleConnections: true</code> required (an Information log notes it).</li><li><code>null</code> or absent = exactly the previous behavior (single discovery connection).</li><li>Every listed name must exist in <code>ConnectionStrings</code> — an unknown name stops startup with an error listing the available names.</li><li>Composite types now resolve <strong>per database</strong>: two databases can have a same-named composite type with different fields and each source serializes with its own definition.</li><li>Watch mode (<code>--watch</code>) polls <strong>each discovery connection</strong>: a routine created/dropped/commented on any listed connection triggers the restart, not just the primary.</li><li>For library (middleware) users: <code>RoutineSource</code> (and <code>IEndpointSource</code> via a default interface member) gains a <code>ConnectionName</code> property, and <code>CreateAndOpenSourceConnection</code> accepts an optional per-source connection name that overrides <code>MetadataQueryConnectionName</code>.</li></ul><p>When two sources discover the <strong>same path</strong> (a routine existing on both databases), the later source wins and a startup warning names both sources and connections — use schema/name filters or a <code>path</code> annotation to disambiguate.</p><p>Use <code>ReadMetadataFromConnections</code> when databases host <em>different</em> routines. For <em>identical</em> databases (replicas, shards), keep using <code>UseMultipleConnections</code> with the <code>connection</code> annotation — single discovery is correct and cheaper there.</p><h4 id="routed-endpoint-verification-verifyroutedendpoints" tabindex="-1">Routed endpoint verification: <code>VerifyRoutedEndpoints</code> <a class="header-anchor" href="#routed-endpoint-verification-verifyroutedendpoints" aria-label="Permalink to &quot;Routed endpoint verification: \`VerifyRoutedEndpoints\`&quot;">​</a></h4><p>Endpoints routed by the <code>connection</code> annotation to a different connection than they were discovered on assume the target database has the same routines. Nothing checked that assumption until the first failing request. Now, opt-in:</p><details class="code-collapsible" open><summary>json</summary><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">{</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">  &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">NpgsqlRest</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> {</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">    &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">RoutineOptions</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> {</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">      &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">VerifyRoutedEndpoints</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> &quot;Warn&quot;</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">    }</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">  }</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div></details><ul><li><code>&quot;None&quot;</code> (default) — no verification.</li><li><code>&quot;Warn&quot;</code> — at startup, one batched existence check per distinct target connection (<code>to_regprocedure</code> for functions/procedures; <code>to_regclass</code> for tables/views when composing <code>CrudSource</code> in the library); every missing routine is logged as a warning naming the routine, the connection, and the endpoints that need it.</li><li><code>&quot;Fail&quot;</code> — same check, but any missing routine stops startup with an aggregated error.</li></ul><p>This checks <strong>content</strong> (does the routine exist over there?) — connectivity of every connection string remains a separate concern covered by <code>ConnectionSettings:TestConnectionStrings</code> (opens and closes the connection). The check verifies existence/signature only (result shapes are not compared), and SQL-file endpoints are skipped (no catalog name to check). Cost: one connection and one round-trip per distinct annotated target connection, only when enabled.</p><h4 id="environment-variable-fallback-values-name-fallback" tabindex="-1">Environment variable fallback values: <code>{!NAME:fallback}</code> <a class="header-anchor" href="#environment-variable-fallback-values-name-fallback" aria-label="Permalink to &quot;Environment variable fallback values: \`{!NAME:fallback}\`&quot;">​</a></h4><p>Environment variable placeholders now support an inline fallback value, completing the placeholder grammar:</p><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Form</th><th>Behavior</th></tr></thead><tbody><tr><td><code>{NAME}</code></td><td>Optional — replaced when the variable is set, left untouched otherwise.</td></tr><tr><td><code>{!NAME}</code></td><td>Required — replaced when the variable is set, startup fails otherwise.</td></tr><tr><td><code>{!NAME:fallback}</code></td><td>Replaced when the variable is set, otherwise the literal <code>fallback</code> text is used — never fails.</td></tr></tbody></table></div></div><p>The fallback starts after the first <code>:</code> and runs to the closing brace, so it may itself contain <code>:</code> (e.g. <code>{!BASE_URL:http://localhost:5000}</code>), but not <code>}</code>. Only the <code>{!</code> form takes a fallback — a plain <code>{NAME:...}</code> is never treated as an env placeholder, which keeps brace-colon content like Serilog format specifiers (<code>{Timestamp:HH:mm:ss}</code>), inline CSS (<code>td{border:1px solid}</code>), and TypeScript object types (<code>{status: number}</code>) intact.</p><p>The default connection string now uses fallbacks matching the standard PostgreSQL defaults for everything except the database name, which stays required:</p><details class="code-collapsible" open><summary>json</summary><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">{</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">  &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">ConnectionStrings</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> {</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">    &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">Default</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> &quot;Host={!PGHOST:localhost};Port={!PGPORT:5432};Database={!PGDATABASE};Username={!PGUSER:postgres};Password={!PGPASSWORD:postgres}&quot;</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">  }</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div></details><p>With no environment configured at all, startup fails with exactly one actionable error — <code>Required environment variable &#39;PGDATABASE&#39; (referenced as &#39;{!PGDATABASE}&#39; in configuration) is not set.</code> Setting only <code>PGDATABASE</code> connects to <code>localhost:5432</code> as <code>postgres</code>/<code>postgres</code>.</p><p>Notes:</p><ul><li>The <code>--config</code> output and <code>--validate</code> resolve fallbacks (the fallback <em>is</em> the value the running application will use), while unset <code>{!NAME}</code> placeholders without a fallback are still kept as literals so the configuration can always be inspected before the environment is set up.</li><li>Works in every configuration value (connection strings, test-runner connections, any typed value — e.g. <code>&quot;Port&quot;: &quot;{!PORT:5432}&quot;</code>).</li></ul><h4 id="the-same-placeholder-rules-in-static-content-and-annotation-values" tabindex="-1">The same placeholder rules in static content and annotation values <a class="header-anchor" href="#the-same-placeholder-rules-in-static-content-and-annotation-values" aria-label="Permalink to &quot;The same placeholder rules in static content and annotation values&quot;">​</a></h4><p>The <code>{!NAME}</code> and <code>{!NAME:fallback}</code> forms now also work in the two request-time substitution systems, with the same grammar and their existing allowlist security model unchanged:</p><ul><li><strong>Static files</strong> (<code>{ &quot;StaticFiles&quot;: { &quot;ParseContentOptions&quot;: { &quot;AvailableEnvVars&quot;: [...] } } }</code>): <code>{!NAME}</code> resolves like <code>{NAME}</code> for listed names; <code>{!NAME:fallback}</code> uses the inline fallback when the listed variable is unset and has no configured default. The same applies to claims: <code>{!claim_name:fallback}</code> uses the fallback when the claim is absent (e.g. anonymous requests). Unlisted names are always left untouched — the strict forms never widen the allowlist.</li><li><strong>Comment annotations and HTTP Custom Types</strong> (<code>{ &quot;NpgsqlRest&quot;: { &quot;AvailableEnvVars&quot;: [...] } }</code>): same rules for response headers, custom parameters, and HTTP custom type URL/body/header values. Routine parameters keep precedence over env vars in both forms, and a <strong>null parameter value now yields the inline fallback</strong>: <code>X-Plan: {!_plan:free}</code> sends <code>free</code> when <code>_plan</code> is null.</li><li>The build-time unknown-placeholder warning understands the new forms and validates the name part, so a typo in <code>{!NAME:fallback}</code> is still caught at startup.</li><li>For library (middleware) users populating <code>NpgsqlRestOptions.SubstitutionEnvironmentVariables</code> directly: register a second <code>&quot;!NAME&quot;</code> key alongside each <code>&quot;NAME&quot;</code> entry that resolved to a real value — the standalone client does this automatically. See the property documentation.</li></ul><h4 id="env-file-loaded-by-default-envfile-env" tabindex="-1"><code>.env</code> file loaded by default (<code>&quot;EnvFile&quot;: &quot;./.env&quot;</code>) <a class="header-anchor" href="#env-file-loaded-by-default-envfile-env" aria-label="Permalink to &quot;\`.env\` file loaded by default (\`&quot;EnvFile&quot;: &quot;./.env&quot;\`)&quot;">​</a></h4><p>The default configuration now ships with:</p><details class="code-collapsible" open><summary>json</summary><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">{</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">  &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">Config</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> {</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">    &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">EnvFile</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> &quot;./.env&quot;</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">  }</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div></details><p>Combined with the new fallback connection string, this makes the minimal setup a single file — create <code>.env</code> next to the configuration with one line, <code>PGDATABASE=mydb</code>, and run <code>npgsqlrest</code>.</p><p>Behavior:</p><ul><li><strong>Variables already present in the process environment always win</strong> — the file only fills in missing ones (the standard dotenv convention). ⚠️ This is a behavior change for existing <code>EnvFile</code> users: before 3.21.0 the file overwrote the environment. Within the file itself, a repeated key keeps its last value.</li><li>The default <code>./.env</code> (relative to the working directory) is <strong>optional</strong>: when the file does not exist, startup logs an information message — <code>Env file ./.env not found, skipping (set Config:EnvFile to null to disable env file loading)</code> — never a warning, so clean production deployments (env vars from the orchestrator, no file) stay warning-free.</li><li>A <strong>custom</strong> <code>EnvFile</code> path that does not exist logs a <strong>warning</strong> — you explicitly named a file that is not there.</li><li>When the file loads, startup logs how many variables it contributed and how many were kept from the real environment: <code>Loaded 3 environment variable(s) from env file ./.env (1 already set in the environment and kept)</code>.</li><li>Set <code>&quot;EnvFile&quot;: null</code> to disable loading entirely. Configurations that omit the <code>EnvFile</code> key keep the previous behavior (no file is loaded) — the <code>./.env</code> default comes from the shipped configuration file, not from code.</li></ul><h4 id="install-skill-install-the-claude-code-skill-from-the-cli" tabindex="-1"><code>--install-skill</code>: install the Claude Code skill from the CLI <a class="header-anchor" href="#install-skill-install-the-claude-code-skill-from-the-cli" aria-label="Permalink to &quot;\`--install-skill\`: install the Claude Code skill from the CLI&quot;">​</a></h4><p>The official <a href="https://vb-consulting.github.io/npgsqlrest/guide/claude-code-skill" target="_blank" rel="noreferrer">Claude Code skill</a> can now be installed directly from the binary, replacing the platform-specific <code>curl</code>/<code>Invoke-WebRequest</code> instructions:</p><details class="code-collapsible" open><summary>console</summary><div class="language-console vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">console</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">npgsqlrest --install-skill          # project scope: ./.claude/skills/npgsqlrest (commit it for the whole team)</span></span>
<span class="line"><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">npgsqlrest --install-skill global   # user scope: ~/.claude/skills/npgsqlrest (available in every project)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div></details><ul><li>Downloads the three skill files (<code>SKILL.md</code>, <code>annotations-reference.md</code>, <code>configuration-reference.jsonc</code>) from the <strong>release branch matching the running version</strong> (e.g. <code>3.21.0</code>), so the skill references always match the installed binary. When that branch is not available, it falls back to <code>master</code> with a printed note.</li><li>All files come from the same git ref and are downloaded fully before anything is written — a network failure never leaves a partial install behind.</li><li>Works the same on every platform; upgrading is re-running the same command after upgrading the binary.</li><li>For tests and enterprise mirrors, the download base is overridable via the <code>NPGSQLREST_SKILL_BASE_URL</code> environment variable (same <code>{base}/{ref}/.claude/skills/npgsqlrest/{file}</code> layout).</li></ul><h4 id="new-cli-logo" tabindex="-1">New CLI logo <a class="header-anchor" href="#new-cli-logo" aria-label="Permalink to &quot;New CLI logo&quot;">​</a></h4><p>The CLI banner (shown by <code>--help</code>, <code>--version</code>, <code>--install-skill</code>, ...) was replaced with a two-tone ANSI-block design and a tagline. The logo now sets UTF-8 console output (guarded), so the block glyphs render correctly on legacy Windows consoles; it never prints in server logs.</p><h3 id="fixes" tabindex="-1">Fixes <a class="header-anchor" href="#fixes" aria-label="Permalink to &quot;Fixes&quot;">​</a></h3><ul><li><strong><code>connection &lt;main-name&gt;</code> annotation now works.</strong> The main connection was excluded from the routable connections dictionary, so routing an endpoint to the main connection <em>by its own name</em> failed every request with a 500 (<code>Connection name ... could not be found</code>). The main connection is now registered under its real name — and resolves to the <strong>same</strong> data source/pool as unrouted requests. The same fix makes <code>ConnectionSettings:MetadataQueryConnectionName</code> accept the main connection&#39;s name (previously a startup error).</li><li><strong>No more duplicate pool for a multi-host main connection.</strong> The <code>&quot;_default&quot;</code> data-source alias used to be a <em>second</em> <code>NpgsqlMultiHostDataSource</code> built for the same connection string; it now references the same instance as the main data source.</li><li><strong>The <code>connection=name</code> annotation form is validated.</strong> The <code>key = value</code> parse path assigned the connection name with no validation at all; both forms now warn at startup when the name is not registered — and the check consults <code>DataSources</code> (multi-host) too, so multi-host-only names no longer produce a false warning.</li><li><strong>Watch mode polls the metadata connection.</strong> The <code>--watch</code> database poller always fingerprinted the primary connection, even when <code>ConnectionSettings:MetadataQueryConnectionName</code> pointed discovery at a different connection — it could watch a database that discovery never read. Pollers now follow each source&#39;s actual discovery connection.</li><li>Connection name matching (<code>ConnectionStrings</code>/<code>DataSources</code> dictionaries built by the client) is now case-insensitive, consistent with <code>IConfiguration</code> key semantics — a lowercased annotation name finds a mixed-case <code>ConnectionStrings</code> entry.</li><li>Fixed the <code>--annotations</code> CLI reference output missing six annotations: <code>single</code>, <code>void</code>, <code>skip</code> (aliases <code>skip_result</code>, <code>no_result</code>), <code>returns</code>, <code>mcp</code> (aliases <code>mcp_name</code>, <code>mcp_description</code>, <code>mcp_desc</code>) and <code>openapi</code>. The annotations themselves were always functional — only the JSON reference output was incomplete.</li></ul>`,44)]))}const g=n(i,[["render",o]]);export{u as __pageData,g as default};
